const express = require('express');
const mongoose = require('mongoose');

async function queryBuilder(filter, projection, sort) {
    try {
        const collection = mongoose.connection.collection('yourCollectionName'); // Replace with your actual collection name

        const queryOptions = {};
        if (projection) {
            queryOptions.projection = projection;
        }
        if (sort) {
            queryOptions.sort = sort;
        }

        const results = await collection.find(filter).setOptions(queryOptions).toArray();
        return results;
    } catch (error) {
        throw new Error('Error executing the query: ' + error.message);
    }
}

// Example usage in an Express route
const app = express();

app.get('/query', async (req, res) => {
    try {
        const filter = req.query.filter ? JSON.parse(req.query.filter) : {};
        const projection = req.query.projection ? JSON.parse(req.query.projection) : null;
        const sort = req.query.sort ? JSON.parse(req.query.sort) : null;

        const results = await queryBuilder(filter, projection, sort);
        res.json(results);
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

